import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useBlockchain } from '../context/BlockchainContext';

const Verify: React.FC = () => {
    const { token } = useAuth();
    const { account } = useBlockchain();
    const [file, setFile] = useState<File | null>(null);
    const [docType, setDocType] = useState('Aadhar Card');
    const [generatedHash, setGeneratedHash] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            setFile(e.target.files[0]);
            setMessage('');
        }
    };

    const submitDocument = async () => {
        if (!file || !token) return;
        setLoading(true);
        try {
            // Simulated IPFS CID for this doc in a real decentralized app
            const ipfsHash = `Qm${Math.random().toString(36).substring(2, 15)}`;

            // Submit to Admin Queue for verification and hashing
            const res = await fetch('http://localhost:5000/api/verify/apply-admin', {
                method: 'POST',
                headers: { 
                    'Content-Type': 'application/json',
                    'x-auth-token': token 
                },
                body: JSON.stringify({
                    documentCIDs: [{
                        fileName: `${docType}`,
                        ipfsHash: ipfsHash
                    }]
                })
            });

            if (res.ok) {
                setMessage(`Document submitted securely to Government Authorities.`);
                setFile(null);
            } else {
                const data = await res.json();
                throw new Error(data.message || 'Submission failed');
            }
        } catch (err: any) {
            setMessage(`Protocol Error: ${err.message}`);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fade-in" style={{ maxWidth: '800px', margin: '0 auto' }}>
            <div style={{ marginBottom: '4rem' }}>
                <h1 style={{ fontSize: '3rem' }}>Verify Identity</h1>
                <p style={{ color: 'var(--text-secondary)', fontSize: '1.2rem' }}>
                    Upload your legal documents to generate permanent cryptographic proofs.
                </p>
            </div>

            <div className="glass" style={{ padding: '4rem' }}>
                <div style={{ display: 'grid', gap: '2.5rem' }}>
                    <div>
                        <label>Document Type</label>
                        <select 
                            value={docType} 
                            onChange={(e) => setDocType(e.target.value)}
                            style={{ 
                                width: '100%', 
                                padding: '1rem', 
                                background: 'rgba(255,255,255,0.05)', 
                                border: '1px solid var(--card-border)',
                                color: '#fff',
                                borderRadius: '8px',
                                fontSize: '1rem'
                            }}
                        >
                            <option value="Aadhar Card">Aadhar Card</option>
                            <option value="PAN Card">PAN Card</option>
                            <option value="Passport">Passport</option>
                            <option value="Driver License">Driver License</option>
                        </select>
                    </div>

                    <div>
                        <label>Identity Document (Image/PDF)</label>
                        <div style={{ 
                            border: '2px dashed var(--card-border)', 
                            padding: '3rem', 
                            textAlign: 'center', 
                            borderRadius: '12px',
                            cursor: 'pointer',
                            position: 'relative',
                            transition: 'var(--transition)'
                        }} className="hover-glass">
                            <input 
                                type="file" 
                                onChange={handleFileChange} 
                                style={{ opacity: 0, position: 'absolute', width: '100%', height: '100%', top: 0, left: 0, cursor: 'pointer' }} 
                            />
                            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📄</div>
                            <p style={{ fontWeight: 500 }}>{file ? file.name : 'Select document file to proceed'}</p>
                            <span style={{ fontSize: '0.8rem', opacity: 0.5 }}>Your data remains local throughout this process.</span>
                        </div>
                    </div>

                    <div style={{ display: 'flex', gap: '1.5rem' }}>
                        <button 
                            onClick={submitDocument} 
                            disabled={!file || loading} 
                            className="btn btn-primary"
                            style={{ flex: 1, padding: '1.2rem' }}
                        >
                            {loading ? 'Submitting...' : 'Submit Document to Government'}
                        </button>
                    </div>

                    {message && (
                        <div style={{ 
                            textAlign: 'center', 
                            fontSize: '0.9rem', 
                            color: message.includes('Error') ? 'var(--error)' : 'var(--success)',
                            fontWeight: 600
                        }}>
                            {message}
                        </div>
                    )}
                </div>
            </div>

            <div style={{ marginTop: '3rem', display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1.5rem' }}>
                <div className="glass" style={{ padding: '2rem' }}>
                    <h4 style={{ marginBottom: '1rem' }}>Secure Submission</h4>
                    <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                        Your document is securely transmitted directly to Government Authorities for review and official cryptographic hash generation.
                    </p>
                </div>
                <div className="glass" style={{ padding: '2rem' }}>
                    <h4 style={{ marginBottom: '1rem' }}>Permanent Proof</h4>
                    <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                        Once verified by an Admin, your document's hash will automatically appear in your Vault, allowing you to instantly prove your identity to Banks.
                    </p>
                </div>
            </div>
        </div>
    );
};

export default Verify;
